svg.script:

function comarcaClicked(comarcaId) {
    var comarca = document.getElementById(comarcaId);
    if (comarca) {
        // Guardar el color original
        var originalColor = comarca.style.fill;

        // Guardar el viewBox original
        var svg = document.getElementsByTagName("svg")[0];
        var originalViewBox = svg.getAttribute("viewBox");

        // Cambiar el color de la comarca pulsada
        comarca.style.fill = "white"; // Cambiar a color rojo

        // Hacer zoom en la comarca
        var bbox = comarca.getBBox();

        // Calcular el centro del bbox
        var centerX = bbox.x + bbox.width / 2;
        var centerY = bbox.y + bbox.height / 2;

        // Establecer un margen adicional para el zoom
        var margin = 20; // Puedes ajustar este valor según sea necesario
        var newWidth = bbox.width + margin * 2; // Ancho con margen
        var newHeight = bbox.height + margin * 2; // Alto con margen

        // Establecer el nuevo viewBox centrado en la comarca
        svg.setAttribute("viewBox", (centerX - newWidth / 2) + " " + (centerY - newHeight / 2) + " " + newWidth + " " + newHeight);

        // Enviar el color original y el viewBox original al Android
        Android.showComarca(comarcaId, originalColor, originalViewBox);
    } else {
        console.error("No se encontró la comarca con ID: " + comarcaId);
    }
}
